const AIRecommendationDeploymentConfiguration = @import("ai_recommendation_deployment_configuration.zig").AIRecommendationDeploymentConfiguration;
const AIRecommendationPerformanceMetric = @import("ai_recommendation_performance_metric.zig").AIRecommendationPerformanceMetric;
const AIRecommendationModelDetails = @import("ai_recommendation_model_details.zig").AIRecommendationModelDetails;
const AIRecommendationOptimizationDetail = @import("ai_recommendation_optimization_detail.zig").AIRecommendationOptimizationDetail;

/// An optimization recommendation generated by an AI recommendation job.
pub const AIRecommendation = struct {
    /// The Amazon Resource Name (ARN) of the benchmark job associated with this
    /// recommendation.
    ai_benchmark_job_arn: ?[]const u8 = null,

    /// The deployment configuration for this recommendation, including the
    /// container image, instance type, instance count, and environment variables.
    deployment_configuration: ?AIRecommendationDeploymentConfiguration = null,

    /// The expected performance metrics for this recommendation.
    expected_performance: ?[]const AIRecommendationPerformanceMetric = null,

    /// Details about the model package associated with this recommendation.
    model_details: ?AIRecommendationModelDetails = null,

    /// The optimization techniques applied in this recommendation.
    optimization_details: ?[]const AIRecommendationOptimizationDetail = null,

    /// A description of the recommendation.
    recommendation_description: ?[]const u8 = null,

    pub const json_field_names = .{
        .ai_benchmark_job_arn = "AIBenchmarkJobArn",
        .deployment_configuration = "DeploymentConfiguration",
        .expected_performance = "ExpectedPerformance",
        .model_details = "ModelDetails",
        .optimization_details = "OptimizationDetails",
        .recommendation_description = "RecommendationDescription",
    };
};
